dashboard.definition:
{
  "title": "Sample Dashboard 2 \u2014 Operations Status Wall",
  "description": "Sample dashboard rendering 24 service tiles using bundled SVG icons via splunk.image \u2014 no icon_library.icon_library viz instances. Demonstrates the lightweight SVG-asset path for many-tile dashboards.",
  "defaults": {},
  "dataSources": {},
  "inputs": {},
  "visualizations": {
    "viz_canvas_bg": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#F5F5F7",
        "strokeColor": "transparent"
      }
    },
    "viz_header_title": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "extraLarge",
        "markdown": "# Sample 2 \u2014 Operations Status Wall\n\n*High-density grid of bundled SVG icons via splunk.image \u00b7 live service health \u00b7 auto-refresh disabled in demo*"
      }
    },
    "viz_header_legend": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#6E6E73",
        "fontFamily": "Helvetica",
        "fontSize": "small",
        "markdown": "**24 services monitored**  \u00b7  \ud83d\udfe2 **20** healthy  \u00b7  \ud83d\udfe1 **3** warning  \u00b7  \ud83d\udd34 **1** critical\n\nIcons rendered directly from the bundled SVG catalog via `splunk.image` (no `icon_library.icon_library` viz)."
      }
    },
    "viz_card_0": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#22C55E",
        "strokeWidth": 2
      },
      "cornerRadius": [
        12,
        12,
        12,
        12
      ]
    },
    "viz_icon_0": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/check_circle.svg"
      }
    },
